const express = require('express');
const http = require('http');
const socketIo = require('socket.io');
const jwt = require('jsonwebtoken');
const bcrypt = require('bcrypt');
const session = require('express-session');
const bodyParser = require('body-parser');

const app = express();
const server = http.createServer(app);
const io = socketIo(server);

const users = {}; // In-memory user storage for demo purposes
const SECRET_KEY = 'your_secret_key'; // Store securely in environment variable

app.use(bodyParser.json());
app.use(session({
    secret: 'session_secret', // Store securely in environment variable
    resave: false,
    saveUninitialized: true,
}));

app.post('/register', async (req, res) => {
    const { username, password } = req.body;
    if (!username || !password) return res.status(400).send('Invalid input');
    
    const hashedPassword = await bcrypt.hash(password, 10);
    users[username] = { password: hashedPassword };
    res.status(201).send('User registered');
});

app.post('/login', async (req, res) => {
    const { username, password } = req.body;
    const user = users[username];
    if (!user || !(await bcrypt.compare(password, user.password))) {
        return res.status(401).send('Authentication failed');
    }
    
    const token = jwt.sign({ username }, SECRET_KEY);
    req.session.token = token;
    res.json({ token });
});

io.use((socket, next) => {
    const token = socket.handshake.auth.token;
    if (!token) return next(new Error('Authentication error'));
    
    jwt.verify(token, SECRET_KEY, (err, decoded) => {
        if (err) return next(new Error('Authentication error'));
        socket.username = decoded.username;
        next();
    });
});

io.on('connection', (socket) => {
    console.log(`${socket.username} connected`);

    socket.on('submitScore', (score) => {
        if (typeof score !== 'number' || score < 0) {
            return socket.emit('error', 'Invalid score');
        }
        // Store score securely in your leaderboard system
        console.log(`Score from ${socket.username}: ${score}`);
    });

    socket.on('disconnect', () => {
        console.log(`${socket.username} disconnected`);
    });
});

server.listen(3000, () => {
    console.log('Server is running on port 3000');
});